SELECT b.*,
       te.actual_name as managerName
FROM t_bracket b
left join t_employee te on b.manager_id = te.employee_id
WHERE b.deleted_flag = #{queryForm.deletedFlag}

AND (INSTR(b.bracket_no,#{queryForm.keyWords})
or INSTR(b.shorthand_code,#{queryForm.keyWords})
or INSTR(b.create_user_name,#{queryForm.keyWords})
)


    AND INSTR(b.bracket_no,#{queryForm.bracketNo})


    AND b.manager_id = #{queryForm.managerId}


    AND b.enterprise_id = #{queryForm.enterpriseId}


    AND INSTR(b.shorthand_code,#{queryForm.shorthandCode})


    AND INSTR(b.type,#{queryForm.type})


    AND b.weight >= #{queryForm.weightStart}


    AND b.weight <= #{queryForm.weightEnd}


    AND b.tonnage >= #{queryForm.tonnageStart}


    AND b.tonnage <= #{queryForm.tonnageEnd}


    AND b.create_user_type = #{queryForm.createUserType}


    AND INSTR(b.create_user_name,#{queryForm.createUserName})


    AND b.audit_status = #{queryForm.auditStatus}


    and DATE_FORMAT(b.create_time, '%Y-%m-%d') >= #{queryForm.createStartTime}


    and DATE_FORMAT(b.create_time, '%Y-%m-%d') <= #{queryForm.createEndTime}


    AND b.bracket_id not in

        #{item}



    AND b.bracket_id in

        #{item}


GROUP BY b.bracket_id

    ORDER BY b.create_time DESC

